import React, { useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup, Tooltip } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import { URGENCY_MAP_COLORS, capitalize } from "../utils/helpers";
import { UrgencyBadge, CategoryBadge } from "../components/Badges";

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png",
  iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png",
});

export default function MapPage({ needs, volunteers, user, onMatchClick }) {
  const [filter, setFilter] = useState("all");
  const [showVols, setShowVols] = useState(true);
  const isAdmin = user?.role === "admin";

  const center = [28.65, 77.23];
  const filteredNeeds = filter === "all" ? needs : needs.filter((n) => n.urgency === filter);

  return (
    <div className="animate-fade-in">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 24 }}>
        <div>
          <h2 style={{ fontSize: 24, fontWeight: 800, color: "var(--text-primary)" }}>Live Incident Map</h2>
          <p style={{ color: "var(--text-secondary)" }}>Real-time spatial distribution of community needs</p>
        </div>
        <div className="filter-row">
          {["all", "critical", "high", "medium", "low"].map((u) => (
            <button key={u} className={`filter-chip ${filter === u ? "active" : ""}`} onClick={() => setFilter(u)}>
              {capitalize(u)}
            </button>
          ))}
          <button className={`filter-chip ${showVols ? "active" : ""}`} onClick={() => setShowVols(!showVols)}>
            {showVols ? "Hide" : "Show"} Responders
          </button>
        </div>
      </div>

      <div style={{ borderRadius: 16, overflow: "hidden", border: "1px solid var(--border)", height: 500, background: "var(--bg-secondary)" }}>
        <MapContainer center={center} zoom={13} style={{ height: "100%", width: "100%" }}>
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
          />
          {filteredNeeds.map((need) => (
            <CircleMarker
              key={need.id}
              center={[need.location.lat, need.location.lng]}
              radius={14}
              fillColor={URGENCY_MAP_COLORS[need.urgency]}
              color={URGENCY_MAP_COLORS[need.urgency]}
              weight={2}
              opacity={0.8}
              fillOpacity={0.4}
            >
              <Tooltip permanent={false}>{need.title}</Tooltip>
              <Popup>
                <div style={{ minWidth: 200, padding: 4 }}>
                  <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 8 }}>{need.title}</div>
                  <div style={{ display: "flex", gap: 4, marginBottom: 8 }}>
                    <UrgencyBadge urgency={need.urgency} />
                  </div>
                  <p style={{ fontSize: 12, marginBottom: 12 }}>{need.description}</p>

                  {isAdmin && need.status !== "completed" && need.status !== "rejected" && (
                    <button 
                      className="btn btn-primary btn-sm" 
                      style={{ width: "100%", fontSize: 11 }}
                      onClick={() => onMatchClick(need.id)}
                    >
                      ⚡ Start Smart Match
                    </button>
                  )}
                </div>
              </Popup>
            </CircleMarker>
          ))}
          {showVols && volunteers.map((vol) => (
            <CircleMarker
              key={vol.id}
              center={[vol.location.lat, vol.location.lng]}
              radius={8}
              fillColor="var(--accent-blue)"
              color="#ffffff"
              weight={2}
              opacity={vol.availability ? 1 : 0.4}
              fillOpacity={vol.availability ? 0.8 : 0.3}
            >
              <Popup>
                <div style={{ padding: 4 }}>
                  <div style={{ fontWeight: 800, fontSize: 14 }}>{vol.name}</div>
                  <div style={{ fontSize: 12, color: vol.availability ? "var(--accent-green)" : "var(--text-muted)", fontWeight: 700, margin: "4px 0" }}>
                    {vol.availability ? "🟢 Ready to respond" : "⏸ Currently busy"}
                  </div>
                  <div style={{ fontSize: 11, color: "var(--text-secondary)" }}>{vol.skills.join(", ")}</div>
                </div>
              </Popup>
            </CircleMarker>
          ))}
        </MapContainer>
      </div>

      <div className="grid-4" style={{ marginTop: 24 }}>
        {[["Critical", "critical"], ["High", "high"], ["Medium", "medium"], ["Low", "low"]].map(([label, u]) => (
          <div key={u} className="metric-card" style={{ padding: 16 }}>
            <div className="metric-label" style={{ color: `var(--urgency-${u})` }}>{label} Incidents</div>
            <div className="metric-value" style={{ fontSize: 24 }}>
              {needs.filter((n) => n.urgency === u).length}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
